const candidates = $("Get candidates").all().map(c => c.json);
const scores = items.map(i => i.json);
const chatId = candidates[0]?.telegram_chat_id;

// Merge candidates with relevance scores
const merged = candidates.map((c, idx) => ({
  ...c,
  relevance_score: scores[idx]?.relevance_score ?? 0,
  reasoning: scores[idx]?.reasoning ?? "",
}));

// Filter: score >= 6, max 3 per idea
const byIdea = {};
const passed = [];
for (const m of merged) {
  byIdea[m.idea_id] = (byIdea[m.idea_id] || 0) + 1;
  if (byIdea[m.idea_id] === 1) {
    passed.push(m);
  } else if (m.relevance_score >= 4 && byIdea[m.idea_id] <= 3) {
    passed.push(m);
  }
}

if (passed.length === 0) {
  return [{ json: {
    has_papers: false,
    telegram_chat_id: chatId,
    user_id: $("Set").item.json.user_id,
  }}];
}

// Group by project
const projects = {};
for (const p of passed) {
  if (!projects[p.project_id]) {
    projects[p.project_id] = { title: p.project_title, ideas: {} };
  }
  if (!projects[p.project_id].ideas[p.idea_id]) {
    projects[p.project_id].ideas[p.idea_id] = { title: p.idea_title, papers: [] };
  }
  projects[p.project_id].ideas[p.idea_id].papers.push({
    title: p.paper_title,
    url: p.paper_url,
    arxiv_id: p.arxiv_id,
    score: p.relevance_score,
    reasoning: p.reasoning,
    paper_id: p.paper_id,
    idea_id: p.idea_id,
  });
}

// Format message
let msg = "📬 Дневной дайджест статей\n";
for (const [pid, proj] of Object.entries(projects)) {
  msg += `\n📁 Проект: ${proj.title}\n`;
  for (const [iid, idea] of Object.entries(proj.ideas)) {
    msg += `\n  💡 Идея: ${idea.title}\n`;
    for (const paper of idea.papers) {
      msg += `    • Статья: ${paper.title}\n`;
      msg += `      Релевантность: ${paper.score}/10 — ${paper.reasoning}\n`;
      msg += `      ${paper.url}\n`;
    }
  }
}

msg = msg.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

return [{
  json: {
    has_papers: true,
    telegram_chat_id: chatId,
    message: msg,
    matched_papers: passed.map(p => ({
      idea_id: p.idea_id,
      paper_id: p.paper_id,
      cosine_similarity: p.cosine_similarity,
      relevance_score: p.relevance_score,
      reasoning: p.reasoning,
    })),
    project_ids: [...new Set(passed.map(p => p.project_id))],
    paper_ids: [...new Set(passed.map(p => p.paper_id))],
    user_id: candidates[0]?.user_id || $("Set").item.json.user_id,
  }
}];

const digest = $("Build digest").first().json;
const tgFirst = $("Send digest").first().json;

const projectArr = "{" + digest.project_ids.join(",") + "}";
const paperArr = "{" + digest.paper_ids.join(",") + "}";

return digest.matched_papers.map(m => ({
  json: {
    user_id: digest.user_id,
    idea_id: m.idea_id,
    paper_id: m.paper_id,
    cosine_similarity: m.cosine_similarity,
    relevance_score: m.relevance_score,
    reasoning: m.reasoning,
    project_ids_pg: projectArr,
    paper_ids_pg: paperArr,
    message: digest.message,
    telegram_message_id: tgFirst.result?.message_id || null,
  }
}));

