INSERT INTO digest_history (user_id, digest_date, project_ids, paper_ids, message_text, telegram_message_id)
VALUES (
  '{{ $json.user_id }}'::UUID,
  CURRENT_DATE,
  '{{ $json.project_ids_pg }}'::UUID[],
  '{{ $json.paper_ids_pg }}'::UUID[],
  $${{ $json.message }}$$,
  {{ $json.telegram_message_id || 'NULL' }}
)
ON CONFLICT DO NOTHING;

